// Tell TypeScript that Frida's global variables are valid




function getPlayerName(p: any): string {
    try {
        // try direct field first
        const direct = p.field("_displayName").value?.content;
        if (direct && direct.trim() !== "") return direct;
    } catch (_) { }

    try {
        const display = p.method("get_displayName").invoke()?.content;
        if (display && display.trim() !== "") return display;
    } catch (_) { }

    try {
        const uid = p.field("_userID").value?.content;
        if (uid && uid.trim() !== "") return uid;
    } catch (_) { }

    return "?";
}
