// SMART ERROR LOGGER  — diagnoses Il2Cpp errors and tells you how to fix them
// ═══════════════════════════════════════════════════════════════════════════
const _errorLog: { time: number; tag: string; msg: string; fix: string }[] = [];
let _errorLogEnabled = true;
let autoSwapDelay = 0;
function diagnoseError(tag: string, err: any): string {
    const msg: string = (err && err.message) ? err.message : String(err);

    // ── couldn't find class ─────────────────────────────────────────────
    const classMatch = msg.match(/couldn't find (?:non-static )?(?:class|type) ([^\s]+)/i)
        ?? msg.match(/class ([^\s]+) not found/i);
    if (classMatch) {
        const cls = classMatch[1];
        return (
            `CLASS NOT FOUND: "${cls}"\n` +
            `  → The game removed or renamed this class in the current build.\n` +
            `  → Open the dump and search for "${cls.split(".").pop()}" to find the new name.\n` +
            `  → If it's gone entirely, wrap the call in: if (YourClass) { ... }`
        );
    }

    // ── couldn't find method ────────────────────────────────────────────
    const methodMatch = msg.match(/couldn't find (?:non-static )?method ([^\s]+) in (?:hierarchy of )?class ([^\s]+)/i)
        ?? msg.match(/method ([^\s]+) not found in ([^\s]+)/i);
    if (methodMatch) {
        const method = methodMatch[1];
        const cls = methodMatch[2];
        return (
            `METHOD NOT FOUND: "${method}" on "${cls}"\n` +
            `  → The game renamed or removed this method in the current build.\n` +
            `  → Search the dump for "class ${cls}" and look for a method that does the same thing.\n` +
            `  → Common renames: AddToBagAck→CheckToAddItem, get_isDevOnly→flags&16, get_Count→GetEnumerator.\n` +
            `  → Wrap in try/catch if the method is optional.`
        );
    }

    // ── couldn't find field ─────────────────────────────────────────────
    const fieldMatch = msg.match(/couldn't find field ([^\s]+) in class ([^\s]+)/i)
        ?? msg.match(/field ([^\s]+) not found/i);
    if (fieldMatch) {
        const field = fieldMatch[1];
        const cls = fieldMatch[2] ?? "?";
        return (
            `FIELD NOT FOUND: "${field}" on "${cls}"\n` +
            `  → Search the dump for "class ${cls}" and find the new field name.\n` +
            `  → Fields are often renamed with a prefix e.g. "_" or "<X>k__BackingField".\n` +
            `  → Try using method("get_${field}").invoke() if a getter exists instead.`
        );
    }

    // ── null / isNull ───────────────────────────────────────────────────
    if (msg.includes("isNull") || msg.includes("null reference") || msg.match(/cannot read propert/i)) {
        return (
            `NULL REFERENCE\n` +
            `  → An object was null when you tried to use it.\n` +
            `  → Add a null check: if (!obj || obj.isNull()) return;\n` +
            `  → Make sure the class instance/singleton is available at the time of the call.\n` +
            `  → If it's a hook, the class may not be loaded yet — move the hook later in execution.`
        );
    }

    // ── wrong number of parameters / overload ──────────────────────────
    if (msg.includes("parameterCount") || msg.includes("overload") || msg.match(/no method with \d+ param/i)) {
        return (
            `WRONG PARAMETER COUNT / OVERLOAD\n` +
            `  → The method signature changed. Check the dump for how many params the method takes now.\n` +
            `  → Use method("name", N) where N = number of parameters.\n` +
            `  → If multiple overloads exist, iterate .overloads() to find the right one.`
        );
    }

    // ── invoke on non-invokable ─────────────────────────────────────────
    if (msg.includes("not a function") || msg.match(/cannot.*invoke/i)) {
        return (
            `INVOKE ERROR\n` +
            `  → You called .invoke() on something that is not a method.\n` +
            `  → Check that the method lookup succeeded before calling invoke().\n` +
            `  → Try: const m = cls.method("name"); if (m) m.invoke();`
        );
    }

    // ── assembly not found ──────────────────────────────────────────────
    if (msg.includes("assembly") && (msg.includes("not found") || msg.includes("couldn't find"))) {
        const asmMatch = msg.match(/assembly[:\s]+([^\s"]+)/i);
        const asm = asmMatch ? asmMatch[1] : "?";
        return (
            `ASSEMBLY NOT FOUND: "${asm}"\n` +
            `  → The DLL was renamed or removed.\n` +
            `  → Check Il2Cpp.domain.assemblies for the correct assembly name.\n` +
            `  → Wrap: try { images["X"] = Il2Cpp.domain.assembly("X").image; } catch(_) {}`
        );
    }

    // ── generic fallback ───────────────────────────────────────────────
    return (
        `UNKNOWN ERROR: ${msg}\n` +
        `  → Check the Frida log for the full stack trace.\n` +
        `  → If it says "Il2CppError", cross-reference the class/method name in the game dump.\n` +
        `  → If it says "TypeError", a variable is null, undefined, or the wrong type.`
    );
}

function smartError(tag: string, err: any): void {
    if (!_errorLogEnabled) { console.error(`[${tag}]`, err); return; }

    const fix = diagnoseError(tag, err);
    const msg = (err && err.message) ? err.message : String(err);
    const time = Date.now();

    _errorLog.push({ time, tag, msg, fix });

    // Always print to Frida log
    console.error(
        `\n╔═ ERROR [${tag}] ════════════════════════════════════\n` +
        `║  ${msg}\n` +
        `╠═ HOW TO FIX ═══════════════════════════════════════\n` +
        `║  ${fix.replace(/\n/g, "\n║  ")}\n` +
        `╚════════════════════════════════════════════════════`
    );
}

function printErrorLog(): void {
    if (_errorLog.length === 0) {
        console.log("[ErrorLog] No errors recorded.");
        return;
    }
    console.log(`\n╔═ ERROR LOG (${_errorLog.length} error${_errorLog.length === 1 ? "" : "s"}) ═══════════════════════`);
    _errorLog.forEach((e, i) => {
        console.log(
            `║ [${i + 1}] tag=${e.tag}\n` +
            `║     err=${e.msg}\n` +
            `║     fix=${e.fix.split("\n")[0]}`
        );
    });
    console.log("╚════════════════════════════════════════════════════");
}

function clearErrorLog(): void {
    _errorLog.length = 0;
    console.log("[ErrorLog] Log cleared.");
}
