const setRigidbodyVelocity = (rb: any, velocity: any) => {
    try {
        // Try to access the field named "velocity" and set its value directly
        // This is a direct memory write to the Rigidbody component
        rb.field("velocity").value = velocity;
    } catch (e) {
        // Fallback: If it's not a field, check if it's a method without 'set_'
        try {
            const m = rb.class.method("set_velocity");
            if (m) m.invoke(velocity);
        } catch (e2) {
            // Last resort: If neither works, the game may have internal 
            // protection on this component.
        }
    }
};
