    function nuclearDespawnAllItems() {
        try {
            const ppgInst = PrefabGen.field("_instance").value;
            if (!ppgInst || ppgInst.isNull()) { sendNotification("PrefabGen not ready", false); return; }

            const rrunner = ppgInst.method("get_runner").invoke();
            if (!rrunner || rrunner.isNull()) { sendNotification("Runner is null", false); return; }

            const allItems = Object.method("FindObjectsByType", 1).inflate(GBOClass).invoke(0);
            let count = 0;

            // Run 5 times at once to ensure authority is taken
            for (let pass = 0; pass < 5; pass++) {
                for (let i = 0; i < allItems.length; i++) {
                    const item = allItems.get(i);
                    if (!item || item.handle.isNull()) continue;
                    try {
                        const netObj = item.method("get_Object").invoke();
                        if (!netObj || netObj.isNull()) continue;
                        netObj.method("RequestStateAuthority").invoke();
                        rrunner.method("Despawn").invoke(netObj);
                        if (pass === 0) count++;
                    } catch (_) { }
                }
            }

            sendNotification("Nuclear despawned " + count + " items (x5)!", false, 2);
        } catch (e) {
            smartError("Nuclear Despawn:", e);
        }
    }



