    function spawnMob(mobName, position, rotation = identityQuaternion) {
        enableMobValidatorBypass();

        const animalCompany = Il2Cpp.domain.assembly("AnimalCompany").image;
        const prefabGenerator = animalCompany.class("AnimalCompany.PrefabGenerator");
        const mobIdClass = animalCompany.class("AnimalCompany.MobID");

        const cleanName = String(mobName).replace(/^mob_prefab\//, "");
        const candidates = [
            cleanName,
            cleanName.replace(/Controller$/, ""),
            cleanName.replace(/_?Controller$/, "")
        ];

        let mobId = null;

        for (const candidate of candidates) {
            try {
                mobId = mobIdClass.field(candidate).value;
                break;
            } catch { }
        }

        if (mobId === null) return false;

        prefabGenerator.method("SpawnMobAsync", 6).overload(
            "AnimalCompany.MobID",
            "UnityEngine.Vector3",
            "UnityEngine.Quaternion",
            "Fusion.NetworkRunner.OnBeforeSpawned",
            "Fusion.NetworkObjectSpawnDelegate",
            "System.String"
        ).invoke(
            mobId,
            position,
            rotation,
            getBeforeMobSpawnDelegate(),
            objectReference,
            Il2Cpp.string("mod")
        );

        return true;
    }
