    function renderGun2(): GunData {
        const StartPosition = rightHandTransform.method("get_position").invoke();
        const Direction = rightHandTransform.method("get_forward").invoke();

        // Calculate endpoint based on current gunLength
        const EndPosition = Vector3.method("op_Addition").invoke(
            StartPosition,
            Vector3.method("op_Multiply").invoke(Direction, gunLength)
        );

        // 1. Pointer: Scaled to 0.1
        if (!GunPointer2 || GunPointer2.isNull()) {
            GunPointer2 = createObject(EndPosition, identityQuaternion, [0.1, 0.1, 0.1], 3, [1, 0, 0, 1]);
            const renderer = getComponent(GunPointer2, Renderer);
            if (renderer && !renderer.isNull()) {
                renderer.method("get_material").invoke().method("set_shader").invoke(SafeUberShader);
            }
        }
        getTransform(GunPointer2).method("set_position").invoke(EndPosition);
        getTransform(GunPointer2).method("set_localScale").invoke([0.1, 0.1, 0.1]); // Ensure slim scale

        // 2. Line: Width set to 0.01
        if (!GunLine2 || GunLine2.isNull()) {
            GunLine2 = addComponent(createObject(zeroVector, identityQuaternion, oneVector, 0, [0, 0, 0, 0]), LineRenderer);
            GunLine2.method("set_positionCount").invoke(2);
            GunLine2.method("get_material").invoke().method("set_shader").invoke(SafeUberShader);
        }
        GunLine2.method("set_startWidth").invoke(0.01);
        GunLine2.method("set_endWidth").invoke(0.01);
        GunLine2.method("SetPosition").invoke(0, StartPosition);
        GunLine2.method("SetPosition").invoke(1, EndPosition);

        return { ray: null, gunPointer: GunPointer2, endPoint: EndPosition };
    }

