    // ══════════════════════════════════════════════════════════════════════════
    // TEXT MENU  —  pure-text wrist panel, no physical buttons
    // Layout:
    //   Line 0:  "NOVA menu"
    //   Line 1:  [tab0] [tab1] [tab2] [tab3] [tab4]
    //   Line 2:  [tab5] [tab6] [tab7] [tab8] [tab9]   (wrap every 5)
    //   ...
    //   separator
    //   Button lines (current tab) — cursor line wrapped in > ... <
    //   separator
    //   Controls hint
    // ══════════════════════════════════════════════════════════════════════════
    function buildTextMenu(): any {
        const catBtns = buttons[currentCategory] ?? [];
        const lines: string[] = [];

        lines.push("  <color=#9B59FF>✦NOVA✦</color>");
        lines.push("<color=#9B59FF>────────────────────</color>");

        if (currentCategory === 0) {
            // Main menu tabs - format every 5 per line
            const TABS_PER_ROW = 1;
            for (let r = 0; r < catBtns.length; r += TABS_PER_ROW) {
                const row = catBtns.slice(r, r + TABS_PER_ROW);
                const rowStr = row.map((btn, li) => {
                    const globalIdx = r + li;
                    const isCur = (globalIdx === textMenuCursor);
                    // Remove " mods" to save space if it exists
                    const shortName = btn.buttonText.replace(" mods", "");
                    return isCur ? `<color=#9B59FF>✦[${shortName}]✦</color>` : `<color=#0000FF> [${shortName}] </color>`;
                }).join(" ");
                lines.push(rowStr);
            }
        } else {
            // Category buttons
            if (catBtns.length === 0) {
                lines.push("  (no buttons)");
            } else {
                // Paginate to 8 items per page
                const pageBtns = catBtns.slice(currentPage * 8, (currentPage + 1) * 8);
                for (let bi = 0; bi < pageBtns.length; bi++) {
                    const globalIdx = currentPage * 8 + bi;
                    const btn = pageBtns[bi];
                    const isCur = (globalIdx === textMenuCursor);
                    const isOn = btn.enabled;
                    const suffix = isOn ? " [ON]" : "";
                    lines.push(isCur ? `<color=#9B59FF>✦ ${btn.buttonText}${suffix} ✦</color>` : `<color=#0000FF>  ${btn.buttonText}${suffix}</color>`);
                }
                if (catBtns.length > 8) {
                    lines.push(`  <color=#9B59FF>(Page ${currentPage + 1}/${Math.ceil(catBtns.length / 8)})</color>`);
                }
            }
        }

        lines.push("<color=#9B59FF>────────────────────</color>");
        if (currentNotification !== "" && time <= notifactionResetTime) {
            lines.push(`<color=#9B59FF>[ ${currentNotification} ]</color>`);
            lines.push("<color=#9B59FF>────────────────────</color>");
        }
        lines.push(" <color=#9B59FF>B=Back  A=Fwd</color>");
        lines.push(" <color=#9B59FF>Grip=Select  Trig=Home</color>");
        lines.push("  <color=#0000FF>guns.lol/novarr</color>");

        const fullText = lines.join("\n");

        // ── Root GameObject ──────────────────────────────────────────────────
        // Build at zero vector first so renderMenuText world-positions are correct local offsets
        const root = createObject(zeroVector, identityQuaternion, oneVector, 3, [0, 0, 0, 0]);
        const rootTF = getTransform(root);
        try { Destroy(getComponent(root, BoxCollider)); } catch (_) { }

        // Canvas
        const canv = createObject(zeroVector, identityQuaternion, oneVector, 3, [0, 0, 0, 0], rootTF);
        const canvas2 = addComponent(canv, Canvas);
        try { Destroy(getComponent(canv, BoxCollider)); } catch (_) { }
        const scaler2 = addComponent(canv, CanvasScaler);
        addComponent(canv, GraphicRaycaster);
        canvas2.method("set_renderMode").invoke(2);
        scaler2.method("set_dynamicPixelsPerUnit").invoke(1000.0);

        const panelH = Math.max(lines.length * 0.018 + 0.01, 0.1);
        renderMenuText(canv, fullText, textColor, [0.12, 0.0, 0.0], [1.2, panelH]);

        // Scale to player scale
        try {
            const scale = GTPlayer.field("<playerScale>k__BackingField").value;
            rootTF.method("set_localScale").invoke(
                Vector3.method("op_Multiply").invoke(
                    Vector3.method("op_Multiply").invoke(rootTF.method("get_localScale").invoke(), scale),
                    menuscale
                )
            );
        } catch (_) { }

        // Now move it to the hand
        rootTF.method("set_position").invoke(leftHandTransform.method("get_position").invoke());
        rootTF.method("set_rotation").invoke(leftHandTransform.method("get_rotation").invoke());

        return root;
    }

    function renderReference() {
        if (righthand) {
            reference = createObject(zeroVector, identityQuaternion, [0.01, 0.01, 0.01], 0, bgColor, leftHandTransform);
        } else {
            reference = createObject(zeroVector, identityQuaternion, [0.01, 0.01, 0.01], 0, bgColor, rightHandTransform);
        }
        referenceCollider = getComponent(reference, Collider);
        getTransform(reference).method("set_localPosition").invoke([0.01, -0.117, 0.05]);
        reference.method("set_layer").invoke(2);
        addComponent(reference, Rigidbody).method("set_isKinematic").invoke(true);
    }
    function kickPlayer(player) {
        const PrefabGenerator = AssemblyCSharp.class("AnimalCompany.NetSessionRPCs");
        console.log("starting kick...")
        console.log("get net session rpc instance")
        const netinst = PrefabGenerator.field("_instance").value;
        if (!netinst) return null;

        console.log("not null, get method and call")
        const kickplr = PrefabGenerator.method("KickPlayer");
        if (!kickplr) return null;
        const rpckickplr = netinst.method("RPC_KickPlayer");
        if (!rpckickplr) return null;
        console.log("methods valid, prepare player");

        const plruserID = player.field("_userID").value;
        if (!plruserID) return null;

        console.log("player user id is valid, call parse of guid")

        const parsedid = Il2Cpp.corlib.class("System.Guid").method("Parse").invoke(plruserID);

        console.log("parse user id: " + parsedid + " calling kick")

        rpckickplr.invoke(parsedid);

        console.log("rpc kick success, call local kick")

        kickplr.invoke(plruserID)

        console.log("success kick player");
        console.log("end kick player");
    }
    function kickAllPlayers() {
        console.log("[+] Getting NetworkRunner instance for kicking...");


        try {
            let kickCount = 0;
            const rigs = Object.method("FindObjectsOfType").inflate(NetPlayer).invoke();
            for (let i = 0; i < rigs.length; i++) {
                const rig = rigs.get(i);
                if (playerIsLocal(rig)) continue;
                kickPlayer(rig)
                kickCount++;
            }

            console.log(`[+] Kicked ${kickCount} players`);
            console.log("=============================");

            // Reset and start new cycle after 3 seconds

        } catch (e) {
            console.log(`[-] Error in kickAllPlayers: ${e}`);

            rightPrimary = false;
        }
    }









    let goopGridDelay = 0;
    function spawnTextAsItemsInFront(text: string) {
        const targetItem = "item_ore_hell";

        const coreModulee = Il2Cpp.domain.assembly("UnityEngine.CoreModule").image;
        const cameraClasss = coreModulee.class("UnityEngine.Camera");
        const cam = cameraClasss.method("get_main").invoke();

        if (!cam || cam.isNull()) {
            pcFlyLog("Could not find Main Camera!");
            return;
        }

        const camTF = cam.method("get_transform").invoke();
        const forward = camTF.method("get_forward").invoke();
        const right = camTF.method("get_right").invoke();
        const up = camTF.method("get_up").invoke();

        // Position: 5 units in front
        const forward5 = Vector3.method("op_Multiply", 2).invoke(forward, 5);
        const pos = camTF.method("get_position").invoke();
        let spawnBase = Vector3.method("op_Addition", 2).invoke(pos, forward5);
        const rot = camTF.method("get_rotation").invoke();

        const scale = 0.25;

        // THE ALPHABET (Now includes a period!)
        const font: Record<string, string[]> = {
            'A': [" XXX ", "X   X", "XXXXX", "X   X", "X   X"],
            'B': ["XXXX ", "X   X", "XXXX ", "X   X", "XXXX "],
            'C': [" XXX ", "X   X", "X    ", "X   X", " XXX "],
            'D': ["XXXX ", "X   X", "X   X", "X   X", "XXXX "],
            'E': ["XXXXX", "X    ", "XXXX ", "X    ", "XXXXX"],
            'F': ["XXXXX", "X    ", "XXXX ", "X    ", "X    "],
            'G': [" XXX ", "X    ", "X  XX", "X   X", " XXX "],
            'H': ["X   X", "X   X", "XXXXX", "X   X", "X   X"],
            'I': [" XXX ", "  X  ", "  X  ", "  X  ", " XXX "],
            'J': ["    X", "    X", "    X", "X   X", " XXX "],
            'K': ["X   X", "X  X ", "XXX  ", "X  X ", "X   X"],
            'L': ["X    ", "X    ", "X    ", "X    ", "XXXXX"],
            'M': ["X   X", "XX XX", "X X X", "X   X", "X   X"],
            'N': ["X   X", "XX  X", "X X X", "X  XX", "X   X"],
            'O': [" XXX ", "X   X", "X   X", "X   X", " XXX "],
            'P': ["XXXX ", "X   X", "XXXX ", "X    ", "X    "],
            'Q': [" XXX ", "X   X", "X   X", "X  XX", " XXXX"],
            'R': ["XXXX ", "X   X", "XXXX ", "X  X ", "X   X"],
            'S': [" XXX ", "X    ", " XXX ", "    X", " XXX "],
            'T': ["XXXXX", "  X  ", "  X  ", "  X  ", "  X  "],
            'U': ["X   X", "X   X", "X   X", "X   X", " XXX "],
            'V': ["X   X", "X   X", "X   X", " X X ", "  X  "],
            'W': ["X   X", "X   X", "X X X", "XX XX", "X   X"],
            'X': ["X   X", " X X ", "  X  ", " X X ", "X   X"],
            'Y': ["X   X", " X X ", "  X  ", "  X  ", "  X  "],
            'Z': ["XXXXX", "   X ", "  X  ", " X   ", "XXXXX"],
            ' ': ["     ", "     ", "     ", "     ", "     "],
            // --- ADDED THE PERIOD HERE ---
            // It's empty except for one block at the bottom left
            '.': ["     ", "     ", "     ", "     ", " XX  "]
        };

        const upperText = text.toUpperCase();

        // --- CENTERING MATH ---
        // 1. Calculate total width (6 columns per letter * scale)
        const totalPhysicalWidth = (upperText.length * 6) * scale;
        // 2. Shift the spawn base to the left by half the width (using a negative multiplier)
        const centerShiftOffset = Vector3.method("op_Multiply", 2).invoke(right, -(totalPhysicalWidth / 2));
        spawnBase = Vector3.method("op_Addition", 2).invoke(spawnBase, centerShiftOffset);

        let cursorX = 0;
        let itemsSpawned = 0;

        for (let i = 0; i < upperText.length; i++) {
            const char = upperText[i];
            const pattern = font[char] || font[' '];

            for (let row = 0; row < 5; row++) {
                for (let col = 0; col < 5; col++) {
                    if (pattern[row][col] === 'X') {
                        const offsetX = Vector3.method("op_Multiply", 2).invoke(right, (cursorX + col) * scale);
                        const offsetY = Vector3.method("op_Multiply", 2).invoke(up, (4 - row) * scale);

                        const offsetTotal = Vector3.method("op_Addition", 2).invoke(offsetX, offsetY);
                        const finalPos = Vector3.method("op_Addition", 2).invoke(spawnBase, offsetTotal);

                        const spawnedItem = spawnItemAtPos(targetItem, finalPos, rot);

                        if (spawnedItem && !spawnedItem.isNull()) {
                            const rb = getComponent(spawnedItem, Rigidbody);
                            if (rb && !rb.isNull()) {
                                rb.method("set_isKinematic").invoke(true);
                            }
                            itemsSpawned++;
                        }
                    }
                }
            }
            // Move cursor for next letter
            cursorX += 6;
        }

        sendNotification("Centered '" + upperText + "' using " + itemsSpawned + " items!", false, 2);
    }

    function normalizeSceneObjectHandle(obj: any): string {
        try {
            if (!obj || obj.isNull?.()) return "";
            const handle = obj.handle;
            if (!handle) return "";
            return handle.toString();
        } catch (_) {
            return "";
        }
    }
    let launchAxisCache: Map<string, string> = new Map();
    function readVec3Components(vec: any): [number, number, number] {
        return [
            (vec.field("x").value as number) || 0,
            (vec.field("y").value as number) || 0,
            (vec.field("z").value as number) || 0
        ];
    }
    function getLaunchForward(sourceTransform: any, referenceTransform: any = null) {
        try {
            const refTf = (referenceTransform && !referenceTransform.isNull?.())
                ? referenceTransform
                : (headCollider && !headCollider.isNull?.() ? getTransform(headCollider) : null);
            const referenceForward = refTf && !refTf.isNull?.()
                ? readVec3Components(refTf.method("get_forward").invoke())
                : [0, 0, 1];
            const cacheKey = normalizeSceneObjectHandle(sourceTransform) || String(sourceTransform);
            const cachedAxis = launchAxisCache.get(cacheKey);
            const readAxis = (axisName: string): any => {
                switch (axisName) {
                    case "forward": return sourceTransform.method("get_forward").invoke();
                    case "-forward": return Vector3.method("op_Multiply", 2).invoke(sourceTransform.method("get_forward").invoke(), -1);
                    case "up": return sourceTransform.method("get_up").invoke();
                    case "-up": return Vector3.method("op_Multiply", 2).invoke(sourceTransform.method("get_up").invoke(), -1);
                    case "right": return sourceTransform.method("get_right").invoke();
                    case "-right": return Vector3.method("op_Multiply", 2).invoke(sourceTransform.method("get_right").invoke(), -1);
                    default: return sourceTransform.method("get_forward").invoke();
                }
            };
            if (cachedAxis) {
                return Vector3.method("Normalize").invoke(readAxis(cachedAxis));
            }
            const candidates = ["forward", "-forward"];
            let bestAxis = "forward";
            let bestScore = -999999;
            for (const axisName of candidates) {
                try {
                    const vec = readAxis(axisName);
                    const v = readVec3Components(vec);
                    const score = (v[0] * referenceForward[0]) + (v[1] * referenceForward[1]) + (v[2] * referenceForward[2]);
                    if (score > bestScore) {
                        bestScore = score;
                        bestAxis = axisName;
                    }
                } catch (_) { }
            }
            launchAxisCache.set(cacheKey, bestAxis);
            return Vector3.method("Normalize").invoke(readAxis(bestAxis));
        } catch (_) {
            try { return sourceTransform.method("get_forward").invoke(); } catch (_) { return [0, 0, 1]; }
        }
    }
    function getGunAimDirection() {
        try {
            const referenceTf = headCollider && !headCollider.isNull?.() ? getTransform(headCollider) : null;
            return getLaunchForward(rightHandTransform, referenceTf);
        } catch (_) {
            return rightHandTransform.method("get_forward").invoke();
        }
    }
    const NullMethod: any = {
        invoke: () => NullObject,
        inflate: () => NullMethod,
        overload: () => NullMethod
    };
    const NullObject: any = {
        handle: { isNull: () => true },
        isNull: () => true,
        method: () => NullMethod,
        field: () => ({ value: NullObject }),
        tryField: () => null,
        tryMethod: () => null,
        class: { type: { name: "NullObject" } }
    };
    let physicsRaycastAllVec4: any = null;
    let physicsRaycastOutVec4: any = null;
    let physicsRaycastOutVec5: any = null;
    function renderGun(overrideLayerMask = null) {
        const StartPosition = rightHandTransform.method("get_position").invoke();
        const Direction = getGunAimDirection();

        const rayStartPosition = Vector3.method("op_Addition").invoke(
            StartPosition,
            Vector3.method("op_Multiply").invoke(Direction, 0.08)
        );

        const layerMask = overrideLayerMask ?? -1;
        let finalRay = null;
        try {
            if (!physicsRaycastAllVec4) {
                physicsRaycastAllVec4 = Physics.method("RaycastAll").overload(
                    "UnityEngine.Vector3",
                    "UnityEngine.Vector3",
                    "System.Single",
                    "System.Int32"
                );
            }
            const hits = physicsRaycastAllVec4.invoke(rayStartPosition, Direction, 512.0, layerMask);
            if (hits && !hits.isNull() && hits.length > 0) {
                let bestDistance = Number.POSITIVE_INFINITY;
                for (let i = 0; i < hits.length; i++) {
                    try {
                        const hit = hits.get(i);
                        if (!hit || hit.isNull?.()) continue;
                        const hitCollider = hit.method("get_collider").invoke();
                        if (!hitCollider || hitCollider.isNull()) continue;
                        const hitPoint = hit.method("get_point").invoke();
                        const distance = Vector3.method("Distance").invoke(hitPoint, StartPosition) as number;
                        if (distance < 0.08 || distance >= bestDistance) continue;
                        bestDistance = distance;
                        finalRay = hit;
                    } catch (_) { }
                }
            }
        } catch (_) { }

        if (!finalRay) {
            try {
                const hitBuf = Il2Cpp.alloc(128);
                if (!physicsRaycastOutVec4) {
                    physicsRaycastOutVec4 = Physics.method("Raycast").overload(
                        "UnityEngine.Vector3",
                        "UnityEngine.Vector3",
                        "UnityEngine.RaycastHit&",
                        "System.Single"
                    );
                }
                if (!physicsRaycastOutVec5) {
                    physicsRaycastOutVec5 = Physics.method("Raycast").overload(
                        "UnityEngine.Vector3",
                        "UnityEngine.Vector3",
                        "UnityEngine.RaycastHit&",
                        "System.Single",
                        "System.Int32"
                    );
                }
                const didHit = overrideLayerMask == null
                    ? physicsRaycastOutVec4.invoke(rayStartPosition, Direction, hitBuf, 512.0)
                    : physicsRaycastOutVec5.invoke(rayStartPosition, Direction, hitBuf, 512.0, layerMask);
                if (didHit) {
                    const hitRef = Il2Cpp.reference(hitBuf);
                    const hitPoint = hitRef.method("get_point").invoke();
                    const distance = Vector3.method("Distance").invoke(hitPoint, StartPosition) as number;
                    if (distance >= 0.08) finalRay = hitRef;
                }
            } catch (_) { }
        }

        if (finalRay) {
            try {
                finalRay.method("get_point").invoke();
            } catch (_) { }
        }

        let EndPosition;
        if (gunLocked) {
            EndPosition = getTransform(lockTarget).method("get_position").invoke();
        } else {
            if (finalRay && !(finalRay.isNull?.() ?? false)) {
                EndPosition = finalRay.method("get_point").invoke();
            } else {
                const farDirection = Vector3.method("op_Multiply").invoke(Direction, 512);
                EndPosition = Vector3.method("op_Addition").invoke(StartPosition, farDirection);
            }
        }

        if (Vector3.method("op_Equality").invoke(EndPosition, zeroVector)) {
            const farDirection = Vector3.method("op_Multiply").invoke(Direction, 512);
            EndPosition = Vector3.method("op_Addition").invoke(StartPosition, farDirection);
        }

        if (GunPointer == null || GunPointer.isNull?.()) {
            GunPointer = createObject(EndPosition, identityQuaternion, [0.1, 0.1, 0.1], 0, [1, 1, 1, 1]);
        }

        GunPointer.method("SetActive").invoke(true);
        const pointerTransform = getTransform(GunPointer);
        pointerTransform.method("set_position").invoke(EndPosition);

        const PointerRenderer = getComponent(GunPointer, Renderer);
        const material = PointerRenderer.method("get_material").invoke();

        material.method("set_shader").invoke(TextShader);

        const pointerColor = (gunLocked || rightTrigger) ? buttonPressedColor : buttonColor;
        material.method("set_color").invoke(pointerColor);

        const collider = getComponent(GunPointer, Collider);
        if (collider != null) {
            Destroy(collider);
        }

        if (GunLine == null || GunLine.isNull?.()) {
            const lineObj = createObject(zeroVector, identityQuaternion, oneVector, 0, [0, 0, 0, 0]);
            GunLine = addComponent(lineObj, LineRenderer);
        } else {
            GunLine.method("get_gameObject").invoke().method("SetActive").invoke(true);
        }

        const lineMaterial = GunLine.method("get_material").invoke();
        lineMaterial.method("set_shader").invoke(TextShader);

        GunLine.method("set_startColor").invoke(bgColor);
        GunLine.method("set_endColor").invoke(bgColor);

        const lineWidth = 0.025;
        GunLine.method("set_startWidth").invoke(lineWidth);
        GunLine.method("set_endWidth").invoke(lineWidth);

        GunLine.method("set_positionCount").invoke(2);
        GunLine.method("set_useWorldSpace").invoke(true);



        GunLine.method("SetPosition").invoke(0, StartPosition);
        GunLine.method("SetPosition").invoke(1, EndPosition);

        if (rightTrigger || gunLocked) {
            const Step = 34;
            GunLine.method("set_positionCount").invoke(Step);
            GunLine.method("SetPosition").invoke(0, StartPosition);
            const dirVec = readVec3Components(Direction);
            const dirMag = Math.sqrt((dirVec[0] * dirVec[0]) + (dirVec[1] * dirVec[1]) + (dirVec[2] * dirVec[2])) || 1;
            const dirNorm: [number, number, number] = [dirVec[0] / dirMag, dirVec[1] / dirMag, dirVec[2] / dirMag];
            let upBasis: [number, number, number] = [0, 1, 0];
            if (Math.abs(dirNorm[1]) > 0.92) upBasis = [1, 0, 0];
            let side: [number, number, number] = [
                (upBasis[1] * dirNorm[2]) - (upBasis[2] * dirNorm[1]),
                (upBasis[2] * dirNorm[0]) - (upBasis[0] * dirNorm[2]),
                (upBasis[0] * dirNorm[1]) - (upBasis[1] * dirNorm[0])
            ];
            let sideMag = Math.sqrt((side[0] * side[0]) + (side[1] * side[1]) + (side[2] * side[2])) || 1;
            side = [side[0] / sideMag, side[1] / sideMag, side[2] / sideMag];
            let swirlUp: [number, number, number] = [
                (dirNorm[1] * side[2]) - (dirNorm[2] * side[1]),
                (dirNorm[2] * side[0]) - (dirNorm[0] * side[2]),
                (dirNorm[0] * side[1]) - (dirNorm[1] * side[0])
            ];
            let swirlUpMag = Math.sqrt((swirlUp[0] * swirlUp[0]) + (swirlUp[1] * swirlUp[1]) + (swirlUp[2] * swirlUp[2])) || 1;
            swirlUp = [swirlUp[0] / swirlUpMag, swirlUp[1] / swirlUpMag, swirlUp[2] / swirlUpMag];

            for (let i = 1; i < (Step - 1); i++) {
                const t = i / (Step - 1);
                const Position = Vector3.method("Lerp").invoke(StartPosition, EndPosition, t);
                const swirlAngle = (time * 9.0) + (t * Math.PI * 10.0);
                const swirlFade = Math.sin(t * Math.PI);
                const swirlRadius = (0.018 + (Math.sin((t * Math.PI * 2.0) + (time * 2.4)) * 0.004)) * swirlFade;
                const offset = [
                    (side[0] * Math.cos(swirlAngle) + swirlUp[0] * Math.sin(swirlAngle)) * swirlRadius,
                    (side[1] * Math.cos(swirlAngle) + swirlUp[1] * Math.sin(swirlAngle)) * swirlRadius,
                    (side[2] * Math.cos(swirlAngle) + swirlUp[2] * Math.sin(swirlAngle)) * swirlRadius
                ];
                const finalPosition = Vector3.method("op_Addition").invoke(Position, offset);
                GunLine.method("SetPosition").invoke(i, finalPosition);
            }

            GunLine.method("SetPosition").invoke(Step - 1, EndPosition);
        }

        return { ray: finalRay ?? NullObject, gunPointer: GunPointer, endPosition: EndPosition };
    }




    function recenterMenu() {
        const menuTransform = getTransform(menu);
        let targetPos, targetRot;

        // --- NEW PC LOGIC INJECTED HERE ---
        if (PCEnabled) {
            // Get the player's head transform
            const headTransform = getTransform(headCollider);
            const headPos = headTransform.method("get_position").invoke();
            const headFwd = headTransform.method("get_forward").invoke();

            // Calculate a position 0.8 units directly in front of the face
            targetPos = Vector3.method("op_Addition").invoke(
                headPos,
                Vector3.method("op_Multiply").invoke(headFwd, 0.8)
            );

            // Match the head's rotation, then apply the UI canvas offset so it faces you
            targetRot = headTransform.method("get_rotation").invoke();
            targetRot = Quaternion.method("op_Multiply").invoke(
                targetRot,
                Quaternion.method("Euler").invoke(-90, 0, 90)
            );
        }
        // --- ORIGINAL VR HAND LOGIC ---
        else if (righthand) {
            targetPos = rightHandTransform.method("get_position").invoke();
            targetRot = rightHandTransform.method("get_rotation").invoke();
            targetRot = Quaternion.method("op_Multiply").invoke(targetRot, Quaternion.method("Euler").invoke(0, 0, 180));
        } else {
            targetPos = leftHandTransform.method("get_position").invoke();
            targetRot = leftHandTransform.method("get_rotation").invoke();
        }

        // Apply the position and rotation (with your existing Lerp logic)
        if (LerpMenu) {
            const menuPos = menuTransform.method("get_position").invoke();
            const distance = Vector3.method("Distance").invoke(menuPos, zeroVector);
            if (distance < 1) {
                menuTransform.method("set_position").invoke(targetPos);
                menuTransform.method("set_rotation").invoke(targetRot);
            } else {
                menuTransform.method("set_position").invoke(Vector3.method("Lerp").invoke(menuPos, targetPos, deltaTime * 15));
                menuTransform.method("set_rotation").invoke(Quaternion.method("Slerp").invoke(menuTransform.method("get_rotation").invoke(), targetRot, deltaTime * 15));
            }
        } else {
            menuTransform.method("set_position").invoke(targetPos);
            menuTransform.method("set_rotation").invoke(targetRot);
        }
    }
