    let pcFlySpeed = 20;
    const pcFlySpeedMin = 5;
    const pcFlySpeedMax = 200;
    const pcFlySpeedStep = 5;
    const pcFlyLookSens = 2.5;
    const PC_VK_MINUS = 0xBD; // '-' key
    const PC_VK_EQUALS = 0xBB; // '=' key
    let pcFlyBtnRef: ButtonInfo | null = null;

    function pcFlyLog(msg: string) {
        console.log("[PC-Fly] " + msg);
    }

    // Win32 fallback — Unity Input never sees keys from injected Frida on this build
    const PC_VK: Record<string, number> = {
        W: 0x57, A: 0x41, S: 0x53, D: 0x44,
        Space: 0x20, LeftShift: 0xA0,
        Slash: 0xBF, Divide: 0x6F, NumpadDivide: 0x6F, Enter: 0x0D, Tab: 0x09,
    };
    let GetAsyncKeyState: any = null;
    let GetCursorPos: any = null;
    let SetCursorPos: any = null;
    let GetSystemMetrics: any = null;
    let pcWin32Ok = false;
    let pcWinMouseX = 0;
    let pcWinMouseY = 0;
    let pcWinMouseInit = false;
    const pcWinWasDown: Record<number, boolean> = {};

    function initPcWin32(): boolean {
        if (pcWin32Ok) return true;
        try {
            const user32 = Process.getModuleByName("user32.dll");
            GetAsyncKeyState = new NativeFunction(user32.getExportByName("GetAsyncKeyState"), "int16", ["int"]);
            GetCursorPos = new NativeFunction(user32.getExportByName("GetCursorPos"), "bool", ["pointer"]);
            SetCursorPos = new NativeFunction(user32.getExportByName("SetCursorPos"), "bool", ["int", "int"]);
            GetSystemMetrics = new NativeFunction(user32.getExportByName("GetSystemMetrics"), "int", ["int"]);
            pcWin32Ok = true;
            pcFlyLog("Win32 input ready (GetAsyncKeyState + GetCursorPos)");
            return true;
        } catch (e) {
            pcFlyLog("Win32 input failed: " + e);
            return false;
        }
    }

    function pcWinKeyDown(vk: number): boolean {
        if (!initPcWin32()) return false;
        try {
            return ((GetAsyncKeyState(vk) as number) & 0x8000) !== 0;
        } catch (_) { return false; }
    }

    function pcWinKeyEdge(vk: number): boolean {
        const down = pcWinKeyDown(vk);
        const was = !!pcWinWasDown[vk];
        pcWinWasDown[vk] = down;
        return down && !was;
    }

    function scanPressedWin32(): string[] {
        const pressed: string[] = [];
        for (const name of Object.keys(PC_VK)) {
            const vk = PC_VK[name];
            if (pcWinKeyDown(vk)) pressed.push(name);
        }
        return pressed;
    }

    function pcGetWinMouseDelta(): { x: number; y: number } {
        if (!initPcWin32() || !GetCursorPos) return { x: 0, y: 0 };
        try {
            const pt = Memory.alloc(8);
            if (!GetCursorPos(pt)) return { x: 0, y: 0 };
            const x = pt.readS32();
            const y = pt.add(4).readS32();
            if (!pcWinMouseInit) {
                pcWinMouseX = x;
                pcWinMouseY = y;
                pcWinMouseInit = true;
                return { x: 0, y: 0 };
            }
            const dx = x - pcWinMouseX;
            const dy = y - pcWinMouseY;
            pcWinMouseX = x;
            pcWinMouseY = y;
            return { x: dx, y: dy };
        } catch (_) { return { x: 0, y: 0 }; }
    }

    const PC_IS_KEY_NAMES = [
        "W", "A", "S", "D", "Space", "LeftShift", "Slash", "Divide", "NumpadDivide",
        "E", "Q", "R", "F", "Escape", "Enter", "Tab",
    ];

    function pcInputSystemUpdate() {
        if (!InputSystemClass) return;
        try { InputSystemClass.method("Update").invoke(); } catch (_) {
            try { InputSystemClass.method("Update", 0).invoke(); } catch (_) { }
        }
    }

    function getKeyboard(): any {
        if (!InputSystemKeyboard) return null;
        try {
            const kb = InputSystemKeyboard.method("get_current").invoke();
            if (kb && !kb.isNull()) return kb;
        } catch (_) { }
        try {
            const all = InputSystemKeyboard.method("get_all").invoke();
            if (all && !all.isNull()) {
                const n = all.method("get_Count").invoke() as number;
                if (n > 0) return all.method("get_Item").invoke(0);
            }
        } catch (_) { }
        return null;
    }

    function getISKeyValue(keyEnumName: string): any {
        try {
            const v = ISKeyClass.field(keyEnumName).value;
            if (typeof v === "number") return v;
            if (v && typeof v.toInt === "function") return v.toInt();
        } catch (_) { }
        try {
            const Enum = Il2Cpp.domain.assembly("mscorlib").image.class("System.Enum");
            return Enum.method("Parse", 2).invoke(ISKeyClass, Il2Cpp.string(keyEnumName));
        } catch (_) { }
        return null;
    }

    function readKeyControlPressed(ctrl: any): boolean {
        if (!ctrl || ctrl.isNull()) return false;
        try { if (!!ctrl.field("isPressed").value) return true; } catch (_) { }
        try { if (!!ctrl.method("get_isPressed").invoke()) return true; } catch (_) { }
        try { if (!!ctrl.field("<isPressed>k__BackingField").value) return true; } catch (_) { }
        try { if (!!ctrl.field("wasPressedThisFrame").value) return true; } catch (_) { }
        try { if (!!ctrl.method("get_wasPressedThisFrame").invoke()) return true; } catch (_) { }
        return false;
    }

    function pcIsKeyPressedIS(keyEnumName: string): boolean {
        if (!pcUseInputSystem || !ISKeyClass) return false;
        pcInputSystemUpdate();
        const kb = getKeyboard();
        if (!kb) return false;
        const keyVal = getISKeyValue(keyEnumName);
        if (keyVal == null) return false;

        try { if (!!kb.method("IsKeyPressed", 1).invoke(keyVal)) return true; } catch (_) { }
        try {
            if (InputSystemClass && !!InputSystemClass.method("IsKeyPressed", 1).invoke(keyVal)) return true;
        } catch (_) { }
        try {
            const ctrl = kb.method("get_Item", 1).invoke(keyVal);
            if (readKeyControlPressed(ctrl)) return true;
        } catch (_) { }

        const propMap: Record<string, string> = {
            W: "wKey", A: "aKey", S: "sKey", D: "dKey",
            Space: "spaceKey", LeftShift: "leftShiftKey", Slash: "slashKey",
            Divide: "numpadDivideKey", NumpadDivide: "numpadDivideKey",
        };
        const prop = propMap[keyEnumName];
        if (prop) {
            try {
                const ctrl = kb.field(prop).value;
                if (readKeyControlPressed(ctrl)) return true;
            } catch (_) { }
        }
        return false;
    }

    function pcWasKeyPressedIS(keyEnumName: string): boolean {
        if (!pcUseInputSystem || !ISKeyClass) return false;
        pcInputSystemUpdate();
        const kb = getKeyboard();
        if (!kb) return false;
        const keyVal = getISKeyValue(keyEnumName);
        if (keyVal == null) return false;

        try { if (!!kb.method("WasKeyPressedThisFrame", 1).invoke(keyVal)) return true; } catch (_) { }
        try {
            if (InputSystemClass && !!InputSystemClass.method("WasKeyPressedThisFrame", 1).invoke(keyVal)) return true;
        } catch (_) { }

        const propMap: Record<string, string> = {
            Slash: "slashKey", Divide: "numpadDivideKey", NumpadDivide: "numpadDivideKey",
            W: "wKey", A: "aKey", S: "sKey", D: "dKey",
            Space: "spaceKey", LeftShift: "leftShiftKey",
        };
        const prop = propMap[keyEnumName];
        if (prop) {
            try {
                const ctrl = kb.field(prop).value;
                if (!ctrl || ctrl.isNull()) return false;
                try { if (!!ctrl.field("wasPressedThisFrame").value) return true; } catch (_) { }
                try { if (!!ctrl.method("get_wasPressedThisFrame").invoke()) return true; } catch (_) { }
            } catch (_) { }
        }
        return false;
    }

    function scanPressedISKeys(): string[] {
        const pressed: string[] = [];
        for (const name of PC_IS_KEY_NAMES) {
            if (pcIsKeyPressedIS(name)) pressed.push(name);
        }
        try {
            const kb = getKeyboard();
            if (kb && !kb.isNull()) {
                const anyKey = kb.field("anyKey").value;
                if (readKeyControlPressed(anyKey)) pressed.push("anyKey");
            }
        } catch (_) { }
        return pressed;
    }

    function scanPressedKeyCodes(): number[] {
        const pressed: number[] = [];
        for (let code = 0; code < 350; code++) {
            if (pcKeyFromCode(code)) pressed.push(code);
        }
        return pressed;
    }

    function dumpPcInput(fromMenu: boolean) {
        resolvePcInput();
        pcFlyLog("========== PC INPUT DUMP ==========");
        try {
            const assemblies = Il2Cpp.domain.assemblies;
            const inputAsms: string[] = [];
            for (let i = 0; i < assemblies.length; i++) {
                try {
                    const n = assemblies[i].name;
                    if (/input|keyboard|mouse/i.test(n)) inputAsms.push(n);
                } catch (_) { }
            }
            pcFlyLog("Input-related assemblies: " + (inputAsms.length ? inputAsms.join(", ") : "(none matched)"));
        } catch (e) { pcFlyLog("Assembly scan failed: " + e); }

        pcInputSystemUpdate();
        pcFlyLog("--- Toggle key (/) probes (Input System) ---");
        pcFlyLog("  IsKeyPressed(Slash): " + pcIsKeyPressedIS("Slash"));
        pcFlyLog("  WasKeyPressed(Slash): " + pcWasKeyPressedIS("Slash"));
        pcFlyLog("  IsKeyPressed(Divide): " + pcIsKeyPressedIS("Divide"));
        try {
            const raw = ISKeyClass.field("Slash").value;
            const parsed = getISKeyValue("Slash");
            pcFlyLog("  Key.Slash raw=" + raw + " parsed=" + parsed);
        } catch (e) { pcFlyLog("  Key.Slash: " + e); }

        pcFlyLog("--- Movement keys (Input System) ---");
        pcFlyLog("  W=" + pcIsKeyPressedIS("W") + " A=" + pcIsKeyPressedIS("A") +
            " S=" + pcIsKeyPressedIS("S") + " D=" + pcIsKeyPressedIS("D") +
            " Space=" + pcIsKeyPressedIS("Space"));

        try {
            const kb = getKeyboard();
            pcFlyLog("  Keyboard device: " + (kb && !kb.isNull() ? "OK" : "NULL"));
            if (kb && !kb.isNull()) {
                try {
                    const ak = kb.field("anyKey").value;
                    pcFlyLog("  anyKey pressed: " + readKeyControlPressed(ak));
                } catch (_) { }
            }
        } catch (e) { pcFlyLog("  Keyboard err: " + e); }

        const pressedIS = scanPressedISKeys();
        pcFlyLog("--- Pressed Input System keys ---");
        pcFlyLog(pressedIS.length ? pressedIS.join(", ") : "(none)");

        initPcWin32();
        pcFlyLog("--- Win32 keys (hold / or WASD then dump) ---");
        pcFlyLog("  Win32 OK: " + pcWin32Ok);
        pcFlyLog("  Slash VK_BF: " + pcWinKeyDown(0xBF));
        pcFlyLog("  W: " + pcWinKeyDown(0x57) + " A: " + pcWinKeyDown(0x41) +
            " S: " + pcWinKeyDown(0x53) + " D: " + pcWinKeyDown(0x44));
        const pressedWin = scanPressedWin32();
        pcFlyLog("  Pressed: " + (pressedWin.length ? pressedWin.join(", ") : "(none — click game window first)"));

        try {
            const loco = getLoco();
            pcFlyLog("--- Player / camera ---");
            pcFlyLog("  GorillaLocomotion: " + (loco && !loco.isNull() ? "OK" : "NULL"));
            const cam = getPcCameraTransform();
            pcFlyLog("  Camera transform: " + (cam && !cam.isNull() ? "OK" : "NULL"));
            try {
                const pc = PCClass.method("get_instance").invoke();
                pcFlyLog("  PlayerController.instance: " + (pc && !pc.isNull() ? "OK" : "NULL"));
            } catch (e) { pcFlyLog("  PlayerController: " + e); }
        } catch (e) { pcFlyLog("  Player/camera err: " + e); }

        try {
            pcFlyLog("--- PlayerController methods (input/key/move) ---");
            const methods = PCClass.methods;
            let count = 0;
            for (let i = 0; i < methods.length && count < 40; i++) {
                const m = methods[i];
                const n = m.name;
                if (/input|key|move|fly|look|cursor|mouse/i.test(n)) {
                    pcFlyLog("  ." + n + "(" + m.parameterCount + ")");
                    count++;
                }
            }
            if (count === 0) pcFlyLog("  (no matching methods in first scan)");
        } catch (e) { pcFlyLog("  PC method scan: " + e); }

        pcFlyLog("pcFlyEnabled=" + pcFlyEnabled + " pcFlyDebugLive=" + pcFlyDebugLive);
        pcFlyLog("========== END DUMP ==========");
        if (fromMenu) {
            sendNotification("PC Input dump in Frida console. Hold / or WASD, dump again to see key codes.", false, 6);
        }
    }

    function pcKeyFromInputSystem(prop: string): boolean {
        const propToEnum: Record<string, string> = {
            wKey: "W", aKey: "A", sKey: "S", dKey: "D",
            spaceKey: "Space", leftShiftKey: "LeftShift", slashKey: "Slash",
        };
        const enumName = propToEnum[prop];
        return enumName ? pcIsKeyPressedIS(enumName) : false;
    }

    function pcKeyFromCode(keyCode: number): boolean {
        if (getKeyIntPtr) {
            try {
                return !!new NativeFunction(getKeyIntPtr, "bool", ["int"])(keyCode);
            } catch (_) { }
        }
        if (Input) {
            try {
                if (KeyCode) {
                    return !!Input.method("GetKey", 1).invoke(keyCode);
                }
                return !!Input.method("GetKeyInt", 1).invoke(keyCode);
            } catch (_) { }
        }
        return false;
    }

    function pcGetKey(keyName: string): boolean {
        initPcWin32();
        const vk = PC_VK[keyName];
        if (vk !== undefined && pcWinKeyDown(vk)) return true;
        if (pcUseInputSystem && ISKeyClass && pcIsKeyPressedIS(keyName)) return true;
        return false;
    }

    function pcIsTogglePressed(): boolean {
        return pcWinKeyDown(0xBF) || pcWinKeyDown(0x6F);
    }

    function pcPollFlyToggle() {
        initPcWin32();
        const edge = pcWinKeyEdge(0xBF) || pcWinKeyEdge(0x6F);
        if (edge) {
            pcFlyLog("Toggle / (Win32) -> " + (pcFlyEnabled ? "OFF" : "ON"));
            setPcFlyEnabled(!pcFlyEnabled);
        }
        if (pcFlyDebugLive && frameCount % 45 === 0) {
            const keys = scanPressedWin32();
            if (keys.length > 0) {
                pcFlyLog("live Win32: " + keys.join(",") + " flyOn=" + pcFlyEnabled);
            }
        }
    }

    function getLoco(): any {
        try {
            const loco = GTPlayerClass.field("<Instance>k__BackingField").value;
            if (loco && !loco.isNull()) return loco;
        } catch (_) { }
        return GTPlayer;
    }

    function getPcCameraTransform(): any {
        try {
            const pc = PCClass.method("get_instance").invoke();
            if (pc && !pc.isNull()) {
                try {
                    const head = pc.method("get_head").invoke();
                    if (head && !head.isNull()) return head;
                } catch (_) { }
                try {
                    const pv = pc.method("get_playerView").invoke();
                    if (pv && !pv.isNull()) {
                        const cam = pv.field("_cameraTransform").value;
                        if (cam && !cam.isNull()) return cam;
                    }
                } catch (_) { }
            }
        } catch (_) { }
        try {
            const camClass = UnityEngineCore.class("UnityEngine.Camera");
            const mainCam = camClass.method("get_main").invoke();
            if (mainCam && !mainCam.isNull()) return mainCam.method("get_transform").invoke();
        } catch (_) { }
        try {
            const camObj = GameObject.method("Find", 1).invoke(Il2Cpp.string("Main Camera"));
            if (camObj && !camObj.isNull()) return camObj.method("get_transform").invoke();
        } catch (_) { }
        try {
            if (headCollider && !headCollider.isNull()) return getTransform(headCollider);
        } catch (_) { }
        return null;
    }

    function getFlyWorldPos(): any {
        const cam = getPcCameraTransform();
        if (cam && !cam.isNull()) return cam.method("get_position").invoke();
        return getTransform(getLoco()).method("get_position").invoke();
    }

    function recenterWinCursor() {
        if (!SetCursorPos || !GetSystemMetrics) return;
        try {
            const cx = Math.floor((GetSystemMetrics(0) as number) / 2);
            const cy = Math.floor((GetSystemMetrics(1) as number) / 2);
            SetCursorPos(cx, cy);
            pcWinMouseX = cx;
            pcWinMouseY = cy;
        } catch (_) { }
    }

    function initPcFlyLookFromRig() {
        try {
            const headTF = getTransform(headCollider);
            const euler = headTF.method("get_eulerAngles").invoke();
            pcFlyYaw = euler.field("y").value as number;
            pcFlyPitch = euler.field("x").value as number;
            if (pcFlyPitch > 180) pcFlyPitch -= 360;
        } catch (_) {
            pcFlyYaw = 0;
            pcFlyPitch = 0;
        }
        pcFlyLookInit = true;
    }

    function applyPcFlyRigLook(mouseDX: number, mouseDY: number) {
        if (!pcFlyLookInit) initPcFlyLookFromRig();
        const sens = 0.15 * pcFlyLookSens;
        pcFlyYaw += mouseDX * sens;
        pcFlyPitch += mouseDY * sens;
        if (pcFlyPitch > 89) pcFlyPitch = 89;
        if (pcFlyPitch < -89) pcFlyPitch = -89;

        const loco = getLoco();
        if (!loco || loco.isNull()) return;

        const bodyTF = getTransform(loco);
        bodyTF.method("set_eulerAngles").invoke([0, pcFlyYaw, 0]);

        try {
            getTransform(headCollider).method("set_eulerAngles").invoke([pcFlyPitch, pcFlyYaw, 0]);
        } catch (_) { }

        try {
            const pc = PCClass.method("get_instance").invoke();
            if (pc && !pc.isNull()) {
                try {
                    const head = pc.method("get_head").invoke();
                    if (head && !head.isNull()) head.method("set_eulerAngles").invoke([pcFlyPitch, pcFlyYaw, 0]);
                } catch (_) { }
                try {
                    const pv = pc.method("get_playerView").invoke();
                    if (pv && !pv.isNull()) {
                        const cam = pv.field("_cameraTransform").value;
                        if (cam && !cam.isNull()) cam.method("set_eulerAngles").invoke([pcFlyPitch, pcFlyYaw, 0]);
                    }
                } catch (_) { }
            }
        } catch (_) { }
    }

    function getPcFlyLookTransform(): any {
        try {
            if (headCollider && !headCollider.isNull()) return getTransform(headCollider);
        } catch (_) { }
        return getTransform(getLoco());
    }

    function setPcFlyEnabled(on: boolean) {
        if (on === pcFlyEnabled) return;
        pcFlyEnabled = on;
        pcFlyLog("setPcFlyEnabled(" + on + ")");
        if (pcFlyBtnRef) pcFlyBtnRef.enabled = on;
        const loco = getLoco();
        const rb = loco ? getComponent(loco, Rigidbody) : null;
        if (on) {
            if (rb && !rb.isNull()) {
                try {
                    preCamFlyUseGravity = rb.method("get_useGravity").invoke();
                    preCamFlyGravityValid = true;
                } catch (_) {
                    preCamFlyGravityValid = false;
                }
                rb.method("set_useGravity").invoke(false);
                try { rb.method("set_gravityScale").invoke(0); } catch (_) { }
                try { rb.method("set_linearVelocity").invoke(zeroVector); } catch (_) { }
                try { rb.method("set_angularVelocity").invoke(zeroVector); } catch (_) { }
            }
            if (Cursor && CursorLockMode) {
                try {
                    Cursor.method("set_lockState").invoke(CursorLockMode.field("Locked").value);
                    Cursor.method("set_visible").invoke(false);
                } catch (_) { }
            }
            pcWinMouseInit = false;
            pcFlyLookInit = false;
            recenterWinCursor();
            sendNotification("PC Fly ON — WASD move, Space/Shift up/down, -/= speed, / toggle.", false, 4);
        } else {
            pcFlyLookInit = false;
            if (rb && !rb.isNull()) {
                rb.method("set_useGravity").invoke(preCamFlyGravityValid ? preCamFlyUseGravity : true);
                try { rb.method("set_isKinematic").invoke(false); } catch (_) { }
                try { rb.method("WakeUp").invoke(); } catch (_) { }
                try { rb.method("set_gravityScale").invoke(1); } catch (_) { }
                try { rb.method("set_linearVelocity").invoke(zeroVector); } catch (_) { }
                try { rb.method("set_angularVelocity").invoke(zeroVector); } catch (_) { }
            }
            if (Cursor && CursorLockMode) {
                try {
                    Cursor.method("set_lockState").invoke(CursorLockMode.field("None").value);
                    Cursor.method("set_visible").invoke(true);
                } catch (_) { }
            }
            sendNotification("PC Fly OFF", false, 2);
        }
    }

    function pcGetMouseDelta(): { x: number; y: number } {
        if (initPcWin32()) return pcGetWinMouseDelta();
        pcInputSystemUpdate();
        if (ISMouseClass) {
            try {
                const mouse = ISMouseClass.method("get_current").invoke();
                if (mouse && !mouse.isNull()) {
                    const delta = mouse.field("delta").value;
                    if (delta && !delta.isNull()) {
                        return {
                            x: delta.field("x").value as number,
                            y: delta.field("y").value as number,
                        };
                    }
                }
            } catch (_) { }
        }
        if (Input) {
            try {
                return {
                    x: Input.method("GetAxis", 1).invoke(Il2Cpp.string("Mouse X")) as number,
                    y: Input.method("GetAxis", 1).invoke(Il2Cpp.string("Mouse Y")) as number,
                };
            } catch (_) { }
        }
        return { x: 0, y: 0 };
    }

    function pcPollFlySpeedKeys() {
        if (!pcFlyEnabled || !initPcWin32()) return;
        if (pcWinKeyEdge(PC_VK_MINUS) || pcWinKeyEdge(0x6D)) {
            pcFlySpeed = Math.max(pcFlySpeedMin, pcFlySpeed - pcFlySpeedStep);
            sendNotification("Fly speed: " + pcFlySpeed, false, 2);
        }
        if (pcWinKeyEdge(PC_VK_EQUALS) || pcWinKeyEdge(0x6B)) {
            pcFlySpeed = Math.min(pcFlySpeedMax, pcFlySpeed + pcFlySpeedStep);
            sendNotification("Fly speed: " + pcFlySpeed, false, 2);
        }
    }
    function tickPcFly() {
        if (!initPcWin32()) return;
        try {
            pcPollFlySpeedKeys();
            const loco = getLoco();
            if (!loco || loco.isNull()) return;
            const tf = getTransform(loco);
            const rb = getComponent(loco, Rigidbody);

            // --- 1. RIGIDBODY ANTI-JITTER FIX ---
            if (rb && !rb.isNull()) {
                try { rb.method("set_useGravity").invoke(false); } catch (_) { }
                try { rb.method("set_isKinematic").invoke(true); } catch (_) { } // Crucial for stopping lobby jitter
                try { rb.method("set_velocity").invoke(zeroVector); } catch (_) { }
                try { rb.method("set_angularVelocity").invoke(zeroVector); } catch (_) { }
            }

            const mouseDelta = pcGetMouseDelta();
            const maxDelta = 120;
            const mdx = Math.max(-maxDelta, Math.min(maxDelta, mouseDelta.x));
            const mdy = Math.max(-maxDelta, Math.min(maxDelta, mouseDelta.y));
            applyPcFlyRigLook(mdx, mdy);
            recenterWinCursor();

            const PC_VK_TAB = 0x09;

            // --- 2. TAB DISCONNECT ---
            if (pcWinKeyEdge(PC_VK_TAB)) {
                try {
                    pcFlyLog("Tab key hit: Spamming disconnect...");
                    const NManagerInst = NManager.method("get_instance").invoke();

                    if (NManagerInst && !NManagerInst.isNull()) {
                        const disconnectBurst = 3;
                        for (let i = 0; i < disconnectBurst; i++) {
                            NManagerInst.method("TryShutdownAndCancelConnecting").invoke();
                        }
                        sendNotification("Spammed Disconnect " + disconnectBurst + " times!", false, 1.5);
                    } else {
                        pcFlyLog("Disconnect failed: NManager is null.");
                    }
                } catch (e) {
                    smartError("Direct Tab disconnect failed:", e);
                }
            }
            if (pcWinKeyEdge(0x30)) { // 0x30 is the '0' key on the number row

                // Choose which one you want to run when you press 0:

                // Option A: Read from the text.txt file
                const fileePath = "C:\\Users\\gabeg\\Downloads\\iiskid\\nova\\nova clent\\text.txt";

                // Open and read the text file
                const filee = new File(fileePath, "r");
                const fileeContent = filee.readText();
                filee.close(); // Close it so Windows releases the file lock

                if (fileeContent && fileeContent.trim().length > 0) {
                    // Pass the text straight into your working pixel art spawner
                    spawnTextAsItemsInFront(fileeContent.trim());
                } else {
                    sendNotification("text.txt is empty!", true, 2);
                }

                // OR Option B: Spawn a specific word instantly
                // spawnTextAsItemsInFront("NOVA"); 
            }
            if (pcWinKeyEdge(0x39)) {
                nuclearDespawnAllItems();
            }
            if (pcWinKeyEdge(0x38)) { // Triggers when you press the '8' key
                try {
                    const me = NetPlayer.method("get_localPlayer").invoke();
                    if (!me || me.handle.isNull()) { sendNotification("Local player not found", false); return; }
                    const targetPos = getTransform(me).method("get_position").invoke();
                    targetPos.field("x").value = -398.276;
                    targetPos.field("y").value = 2.223;
                    targetPos.field("z").value = -399.053;
                    _selfRPCBypass = false;
                    selfRPC(() => me.method("RPC_Teleport").invoke(targetPos));
                    sendNotification("Teleported to Spawn!", false, 2);

                } catch (e) {
                    _selfRPCBypass = false;
                    smartError("Spawn Teleport error:", e);
                }
            }
            // --- 3. ENTER SPAWN ---
            try {
                // 0x0D is the raw Virtual Key code for Enter
                const isEnterDown = ((GetAsyncKeyState(0x0D) as number) & 0x8000) !== 0;

                if (isEnterDown) {
                    pcFlyLog("Direct Enter detected! Spawning...");

                    const spawnPos = rightHandTransform.method("get_position").invoke();
                    const rot = rightHandTransform.method("get_rotation").invoke();
                    const targetItem = "item_fish_nebula_fish";
                    const spawnCount = 50;

                    for (let i = 0; i < spawnCount; i++) {
                        spawnItemAtPos(targetItem, spawnPos, rot);
                    }

                    sendNotification("Spawned " + spawnCount + " Cases!", false, 1);
                }
            } catch (e) {
                smartError("Direct Enter check failed:", e);
            }

            // --- 4. MOVEMENT CALCULATION ---
            const bodyTF = getTransform(loco);
            let moveDir = Vector3.method("get_zero").invoke();
            const fwdFlat = bodyTF.method("get_forward").invoke();
            const rightFlat = bodyTF.method("get_right").invoke();
            const worldUp = Vector3.method("get_up").invoke();

            if (pcGetKey("W")) moveDir = Vector3.method("op_Addition").invoke(moveDir, fwdFlat);
            if (pcGetKey("S")) moveDir = Vector3.method("op_Subtraction", 2).invoke(moveDir, fwdFlat);
            if (pcGetKey("D")) moveDir = Vector3.method("op_Addition").invoke(moveDir, rightFlat);
            if (pcGetKey("A")) moveDir = Vector3.method("op_Subtraction", 2).invoke(moveDir, rightFlat);
            if (pcGetKey("Space")) moveDir = Vector3.method("op_Addition").invoke(moveDir, worldUp);
            if (pcGetKey("LeftShift")) moveDir = Vector3.method("op_Subtraction", 2).invoke(moveDir, worldUp);

            const mx = moveDir.field("x").value as number;
            const my = moveDir.field("y").value as number;
            const mz = moveDir.field("z").value as number;
            const mag = Math.sqrt(mx * mx + my * my + mz * mz);

            if (mag > 0.01) {
                const norm = Vector3.method("Normalize").invoke(moveDir);

                // Safe DeltaTime lookup
                let currentDelta = 0.016;
                try {
                    const TimeClass = Il2Cpp.domain.assembly("UnityEngine.CoreModule").image.class("UnityEngine.Time");
                    currentDelta = TimeClass.method("get_deltaTime").invoke() as number;
                } catch (_) { }

                const moveAmount = Vector3.method("op_Multiply", 2).invoke(norm, pcFlySpeed * currentDelta);
                const curPos = bodyTF.method("get_position").invoke();
                const newPos = Vector3.method("op_Addition", 2).invoke(curPos, moveAmount);

                // Update local transform smoothly
                bodyTF.method("set_position").invoke(newPos);

                // Keep velocity dead so physics don't override the manual movement
                if (rb && !rb.isNull()) setRigidbodyVelocity(rb, zeroVector);
            }
        } catch (err) { smartError("PC Fly:", err); }
    }
